parameters.jsCode:
// Convert plain text draft to professional HTML email with corporate signature
const draft = $('Guardrails: Post RAG').first().json.guardrailsInput || '';
const emailData = $('Gmail Trigger').first().json;

// Convert each line to an HTML paragraph, escape HTML entities
const lines = draft.split('\n');
let htmlBody = '';
for (const line of lines) {
  if (line.trim() === '') {
    htmlBody += '<br>';
  } else {
    const escaped = line.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    htmlBody += '<p style="margin: 0 0 8px 0;">' + escaped + '</p>';
  }
}

const html = '<div style="font-family: Arial, Helvetica, sans-serif; font-size: 14px; color: #333333; line-height: 1.6;">'
  + htmlBody
  + '<br>'
  + '<div style="border-top: 2px solid #1B2A4A; padding-top: 12px; margin-top: 20px;">'
  + '<p style="margin: 0; font-weight: bold; color: #1B2A4A;">ABC Company</p>'
  + '<p style="margin: 2px 0; font-size: 12px; color: #666;">hello@abccompany.io</p>'
  + '<p style="margin: 2px 0; font-size: 12px; color: #666;">Colombo | London | Melbourne</p>'
  + '<p style="margin: 2px 0;"><a href="https://www.abccompany.io" style="color: #2C5282; font-size: 12px;">www.abccompany.io</a></p>'
  + '</div>'
  + '</div>';

return [{
  json: {
    html_reply: html,
    plain_reply: draft,
    subject: emailData.subject || '',
    message_id: emailData.message_id || '',
    thread_id: emailData.thread_id || '',
    sender_email: emailData.sender_email || '',
    attempts: $json.attempts || 1
  }
}];

